const staticData = $getWorkflowStaticData('global');
staticData.accumulator = [];
const now = new Date();
const runId = `run_${now.toISOString().replace(/[-:T.Z]/g, '').slice(0, 14)}`;

// =============================================================
// SOURCES — single source of truth. Add or remove freely.
// Each entry automatically wires into:
//   1) the Firecrawl site: operators in the search query (built below)
//   2) source normalization in 'Parse Candidates'
//   3) source-weight sort in 'Dedup + Cap Candidates'
// Fields:
//   name   — display name shown in tables and emails
//   match  — URL substring used to recognize listings from this source
//   weight — 0.0 to 1.0; higher = surfaces first when capacity is limited
// =============================================================
const sources = [
  { name: 'remoteok.com',       match: 'remoteok.com',       weight: 1.0 },
  { name: 'weworkremotely.com', match: 'weworkremotely.com', weight: 0.9 },
  { name: 'himalayas.app',      match: 'himalayas.app',      weight: 0.9 },
  { name: 'jobspresso.co',      match: 'jobspresso.co',      weight: 0.8 },
  { name: '4dayweek.io',        match: '4dayweek.io',        weight: 0.6 }
];
const siteClauses = '(' + sources.map(s => 'site:' + s.match).join(' OR ') + ')';

const config = {
  run_id: runId,
  run_timestamp_utc: now.toISOString(),
  dry_run: false,
  criteria: {
    role_keywords: ['senior backend engineer', 'staff backend engineer', 'backend engineer'],
    stack_required: ['python', 'django'],
    stack_preferred: ['postgresql', 'postgres', 'redis', 'aws'],
    experience_years_target: 8,
    salary_min_eur: 90000,
    deal_breakers: ['on-site only', 'on site only', 'requires us citizenship', 'crypto', 'web3', 'blockchain'],
    nice_to_have: ['4-day week', 'four-day week', 'open source', 'series a', 'series b', 'series c'],
    max_listing_age_days: 7
  },
  sources,
  firecrawl: {
    search_query: `\"senior backend engineer\" python django remote ${siteClauses} -crypto -web3`,
    search_limit: 24
  },
  // =============================================================
  // DELIVERY — set these once. Read by Send Weekly Digest + Upload CV to Drive.
  // =============================================================
  delivery: {
    recipient_email: 'your-email@example.com',
    drive_folder_id: 'YOUR_GOOGLE_DRIVE_FOLDER_ID'
  },
  candidate_cap: 3,
  deliver_top_n: 10
};
return [{ json: config }];

const raw = $input.all();
const config = $('Config + Run Context').first().json;
const sources = config.sources || [];
const seen = new Set();
const candidates = [];
for (const item of raw) {
  const j = item.json || {};
  let resultArr = [];
  if (j.data && Array.isArray(j.data.web)) resultArr = j.data.web;
  else if (j.data && Array.isArray(j.data)) resultArr = j.data;
  else if (Array.isArray(j.web)) resultArr = j.web;
  else if (Array.isArray(j.results)) resultArr = j.results;
  else if (Array.isArray(j)) resultArr = j;
  for (const r of resultArr) {
    const url = r.url || r.link || r.source_url;
    if (!url || seen.has(url)) continue;
    seen.add(url);
    // Source normalization driven by Config.sources — single source of truth.
    let source = 'unknown';
    const urlLower = url.toLowerCase();
    for (const s of sources) {
      if (s.match && urlLower.includes(s.match.toLowerCase())) { source = s.name; break; }
    }
    candidates.push({
      listing_url: url,
      title: r.title || r.name || '',
      description_snippet: r.description || r.snippet || (r.markdown || '').slice(0, 400),
      source
    });
  }
}
return candidates.map(c => ({ json: { ...c, run_id: config.run_id, run_timestamp_utc: config.run_timestamp_utc } }));

const candidates = $('Parse Candidates').all().map(i => i.json);
const config = $('Config + Run Context').first().json;

// Get Seen Roles may error on empty table — guard against that
let seenRows = [];
try {
  seenRows = $('Get Seen Roles').all().map(i => i.json).filter(r => r && typeof r === 'object');
} catch (e) {
  seenRows = [];
}

// A seen row has listing_url + first_seen_utc. A passthrough candidate won't have first_seen_utc.
// Only treat rows with first_seen_utc as truly seen.
const seenSet = new Set(seenRows.filter(r => r.first_seen_utc).map(r => r.listing_url).filter(Boolean));

const fresh = candidates.filter(c => !seenSet.has(c.listing_url));
const sourceWeights = Object.fromEntries(config.sources.map(s => [s.name, s.weight]));
fresh.sort((a, b) => (sourceWeights[b.source] || 0) - (sourceWeights[a.source] || 0));
const capped = fresh.slice(0, config.candidate_cap);
return capped.map(c => ({ json: { ...c, run_id: config.run_id, run_timestamp_utc: config.run_timestamp_utc } }));

parameters.text:
=The JD has been pre-scraped. Extract the 16-field schema from the JD markdown below.

CANDIDATE:
- URL: {{ $json.listing_url }}
- Title: {{ $json.title }}
- Source: {{ $json.source }}
- JD length: {{ $json.jd_markdown_length }} chars

JD MARKDOWN:
{{ $json.jd_markdown }}

Return ONLY the structured output.

parameters.jsCode:
const parsed = $json.output || $json;
const candidate = $('Loop Over Candidates').item.json;
const config = $('Config + Run Context').first().json;
const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.accumulator)) staticData.accumulator = [];
const stackMatched = (parsed.stack_matched_csv || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
const stackMissing = (parsed.stack_missing_csv || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
const obsFacts = (parsed.observed_facts_semicolon || '').toLowerCase();
let filtered = false, reasonCode = '', reasonQuote = '';
if (parsed.deal_breaker_hit === true || parsed.deal_breaker_hit === 'true') { filtered = true; reasonCode = 'deal_breaker:' + (parsed.deal_breaker_reason || 'unknown'); reasonQuote = parsed.deal_breaker_quote || ''; }
if (!filtered && parsed.salary_max_eur > 0 && parsed.salary_max_eur < config.criteria.salary_min_eur && parsed.salary_confidence === 'high') { filtered = true; reasonCode = 'salary_below_threshold'; reasonQuote = `Salary ${parsed.salary_min_eur}-${parsed.salary_max_eur} EUR`; }
if (!filtered && parsed.listing_posted_date && /^\d{4}-\d{2}-\d{2}/.test(parsed.listing_posted_date)) { const ageDays = (Date.now() - new Date(parsed.listing_posted_date).getTime()) / 86400000; if (ageDays > config.criteria.max_listing_age_days) { filtered = true; reasonCode = 'listing_too_old'; reasonQuote = `Posted ${parsed.listing_posted_date}, ${Math.round(ageDays)}d ago`; } }
if (!filtered && !['remote_anywhere', 'remote_eu', 'remote_specific_region'].includes(parsed.remote_type)) { filtered = true; reasonCode = 'location_mismatch:' + (parsed.remote_type || 'unclear'); reasonQuote = `remote_type=${parsed.remote_type}`; }
let score = 40;
const stackKeywords = ['python', 'django', 'postgresql', 'postgres', 'redis', 'aws'];
for (const k of stackKeywords) if (stackMatched.some(s => s.includes(k))) score += 8;
score = Math.min(score, 80);
if (!stackMatched.some(s => s.includes('python'))) score -= 15;
if (!stackMatched.some(s => s.includes('django'))) score -= 15;
if (parsed.salary_min_eur >= config.criteria.salary_min_eur && parsed.salary_confidence === 'high') score += 10;
if (parsed.salary_source === 'unavailable') score -= 5;
if (['remote_eu', 'remote_anywhere'].includes(parsed.remote_type)) score += 5;
const fourDayWeek = /4-?day|four-?day/i.test(obsFacts) || candidate.source === '4dayweek.io';
if (fourDayWeek) score += 5;
if (/open.?source/i.test(obsFacts)) score += 3;
if (/series\s+[abc]/i.test(obsFacts)) score += 3;
if (parsed.listing_posted_date && /^\d{4}-\d{2}-\d{2}/.test(parsed.listing_posted_date)) { const ageDays = (Date.now() - new Date(parsed.listing_posted_date).getTime()) / 86400000; if (ageDays < 3) score += 4; }
score = Math.max(0, Math.min(100, score));
const band = score >= 75 ? 'High' : score >= 55 ? 'Medium' : 'Low';
const whyNotParts = [];
if (stackMissing.length) whyNotParts.push(`Missing: ${stackMissing.slice(0, 3).join(', ')}.`);
if (parsed.salary_confidence !== 'high') whyNotParts.push(`Salary ${parsed.salary_confidence || 'unknown'} — verify.`);
if (parsed.remote_type === 'remote_specific_region') whyNotParts.push(`Remote scoped to a region — check timezone.`);
const whyNot = whyNotParts.length ? whyNotParts.join(' ') : 'No obvious red flags at listing level.';
let postedDisplay, ageSource;
if (parsed.listing_posted_date && /^\d{4}-\d{2}-\d{2}/.test(parsed.listing_posted_date)) { const ageDays = Math.round((Date.now() - new Date(parsed.listing_posted_date).getTime()) / 86400000); postedDisplay = `${ageDays}d ago (${parsed.listing_posted_date})`; ageSource = 'listing_date'; } else if (parsed.listing_posted_date) { postedDisplay = parsed.listing_posted_date; ageSource = 'recency_label'; } else { postedDisplay = `first seen ${config.run_timestamp_utc.split('T')[0]}`; ageSource = 'first_seen'; }
const out = { listing_url: candidate.listing_url, source: candidate.source, company: parsed.company || 'unknown', role: parsed.role || candidate.title || 'unknown', location: parsed.location || 'unknown', remote_type: parsed.remote_type || 'unclear', posted_display: postedDisplay, listing_posted_date: parsed.listing_posted_date || '', age_source: ageSource, stack_matched_csv: parsed.stack_matched_csv || '', stack_missing_csv: parsed.stack_missing_csv || '', salary_min_eur: parsed.salary_min_eur || 0, salary_max_eur: parsed.salary_max_eur || 0, salary_source: parsed.salary_source || 'unavailable', salary_confidence: parsed.salary_confidence || 'none', observed_facts: parsed.observed_facts_semicolon || '', why_it_fits: parsed.why_it_fits || '', why_not: whyNot, four_day_week: fourDayWeek, fit_score: score, fit_band: band, filtered, reason_code: reasonCode, reason_quote: reasonQuote, run_id: config.run_id, discovered_date: config.run_timestamp_utc, status: 'new' };
staticData.accumulator.push(out);
return [{ json: out }];

const staticData = $getWorkflowStaticData('global');
const all = Array.isArray(staticData.accumulator) ? staticData.accumulator : [];
const kept = all.filter(r => !r.filtered).sort((a,b) => b.fit_score - a.fit_score);
const filtered = all.filter(r => r.filtered);
const delivered = kept.slice(0, 10).map((r, idx) => ({ ...r, rank: idx + 1 }));
const config = $('Config + Run Context').first().json;
return [{ json: { run_id: config.run_id, run_timestamp_utc: config.run_timestamp_utc, week_of: config.run_timestamp_utc.split('T')[0], total_candidates: all.length, delivered_count: delivered.length, filtered_count: filtered.length, high_band_count: delivered.filter(r => r.fit_band === 'High').length, delivered, filtered } }];

const d = $json;
const { delivered, filtered, week_of, total_candidates, delivered_count, filtered_count, high_band_count } = d;
const bandColor = { High: '#1f7a3a', Medium: '#8a6d00', Low: '#6b7280' };
const renderRole = (r) => {
  const applyBtn = `<a href="${r.listing_url}" style="display:inline-block;background:#1f3b5b;color:#fff;padding:8px 14px;border-radius:4px;font-weight:600;text-decoration:none;font-size:13px;margin-right:8px">Apply →</a>`;
  const cvBtn = r.tailored_cv_url ? `<a href="${r.tailored_cv_url}" target="_blank" style="display:inline-block;background:#fff;color:#1f3b5b;padding:7px 13px;border:1px solid #1f3b5b;border-radius:4px;font-weight:600;text-decoration:none;font-size:13px">View tailored CV →</a>` : '';
  return `<tr><td style="padding:14px 16px;border-left:3px solid ${bandColor[r.fit_band]};background:#fafafa;border-radius:4px"><div style="display:flex;justify-content:space-between;align-items:baseline"><strong style="font-size:15px">#${r.rank} · ${r.company}</strong><span style="font-size:12px;color:${bandColor[r.fit_band]};font-weight:600">${r.fit_band} · ${r.fit_score}/100</span></div><div style="font-size:13px;color:#444;margin:2px 0 8px">${r.role} · ${r.location} · ${r.posted_display}</div><div style="font-size:13px;line-height:1.5"><strong>Why it fits:</strong> ${r.why_it_fits}<br><strong style="color:#6b7280">Worth checking:</strong> <span style="color:#6b7280">${r.why_not}</span><br><strong>Salary:</strong> ${r.salary_source === 'unavailable' ? 'not listed' : 'EUR ' + (r.salary_min_eur||'?') + '-' + (r.salary_max_eur||'?') + ' (' + r.salary_confidence + ')'} ${r.four_day_week ? ' · <em>4-day week</em>' : ''}</div><div style="margin-top:12px">${applyBtn}${cvBtn}</div></td></tr>`;
};
const highs = delivered.filter(r => r.fit_band === 'High');
const mediums = delivered.filter(r => r.fit_band === 'Medium');
const lows = delivered.filter(r => r.fit_band === 'Low');
const section = (title, roles) => roles.length === 0 ? '' : `<h3 style="margin:24px 0 10px;font-size:12px;letter-spacing:0.1em;text-transform:uppercase;color:#6b7280">${title}</h3><table style="width:100%;border-collapse:separate;border-spacing:0 8px">${roles.map(renderRole).join('')}</table>`;
const filteredOutSection = filtered.length === 0 ? '' : `<details style="margin-top:30px;padding:12px 16px;background:#f7f7f5;border-radius:4px"><summary style="font-size:13px;color:#6b7280;cursor:pointer">See the ${filtered.length} I ruled out (and the exact quote that did it)</summary><table style="margin-top:10px;width:100%;font-size:12px">${filtered.slice(0,20).map(f => '<tr><td style="padding:6px 0;border-bottom:1px solid #e5e7eb"><strong>' + (f.company||'?') + '</strong> · ' + (f.role||'?') + '<br><em style="color:#6b7280">' + f.reason_code + '</em><br><span style="color:#888;font-size:11px">"' + (f.reason_quote||'').slice(0,180) + '"</span></td></tr>').join('')}</table></details>`;
const opening = high_band_count > 0 ? `${high_band_count} strong ${high_band_count === 1 ? 'match' : 'matches'} this week. Enough to move on.` : delivered_count > 0 ? `No High-band roles this week, but ${delivered_count} defensible ${delivered_count === 1 ? 'match' : 'matches'} to scan.` : `Zero matches this week. That's the filter working, not failing.`;
const html = `<!DOCTYPE html><html><body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;color:#0e1216;max-width:680px;margin:0 auto;padding:24px;line-height:1.5"><p style="font-size:16px;margin-bottom:4px">Morning Daniel,</p><p style="font-size:15px;margin-top:0;color:#3a4048">${opening}<br>${total_candidates} listings checked · ${delivered_count} delivered · ${filtered_count} filtered with evidence.<br><span style="font-size:12px;color:#6b7280">Each role has a tailored CV ready — open, review, save as PDF.</span></p>${section('The ones to look at first', highs)}${section('Worth a look', mediums)}${section('Optional', lows)}${filteredOutSection}<p style="margin-top:30px;font-size:12px;color:#6b7280;border-top:1px solid #e5e7eb;padding-top:12px">Finding the right role takes time, not effort. You're doing the work — let me do the sifting.<br><em>Week of ${week_of} · run ${d.run_id}</em></p></body></html>`;
return [{ json: { ...d, email_subject: `Your Monday roles, Daniel — ${delivered_count} found, ${high_band_count} ready to apply`, email_html: html } }];

// Merge the Firecrawl scrape markdown back into the candidate item
const candidate = $('Loop Over Candidates').item.json;
const scrape = $json || {};
const markdown = scrape.data?.markdown || scrape.markdown || scrape.data?.content || '';
const jdSnippet = String(markdown).slice(0, 8000);
return [{ json: { ...candidate, jd_markdown: jdSnippet, jd_markdown_length: jdSnippet.length } }];

const rawText = $json.text || $json.output || '';
const cvHtml = rawText.replace(/^```html\s*/i,'').replace(/```\s*$/,'').trim();
const candidate = $('Loop Over Candidates').item.json;
const score = $('Score + Decide').item.json;
const safe = (s) => String(s||'unknown').replace(/[^a-z0-9]+/gi,'_').replace(/^_+|_+$/g,'').slice(0,40);
const fileName = `CV_${safe(score.company)}_${safe(score.role)}.html`;
return [{
  json: { cv_html: cvHtml, file_name: fileName, listing_url: candidate.listing_url },
  binary: {
    data: {
      data: Buffer.from(cvHtml, 'utf8').toString('base64'),
      mimeType: 'text/html',
      fileName: fileName,
      fileExtension: 'html'
    }
  }
}];

const prep = $('Prep CV Binary').item.json;
const cvHtml = prep.cv_html || '';
const driveUrl = $json.webViewLink || $json.webContentLink || '';
const candidate = $('Loop Over Candidates').item.json;
const score = $('Score + Decide').item.json;
const staticData = $getWorkflowStaticData('global');
const acc = Array.isArray(staticData.accumulator) ? staticData.accumulator : [];
const row = acc.find(r => r.listing_url === candidate.listing_url);
if (row) { row.tailored_cv_html = cvHtml; row.tailored_cv_url = driveUrl; }
return [{ json: { ...score, tailored_cv_html: cvHtml, tailored_cv_url: driveUrl, text: cvHtml } }];
